// Full parameter declaration with all optional fields
{
  "logAnalyticsWorkspaceId": {
    "type": "String",
    "metadata": {
      "displayName": "Log Analytics Workspace ID",
      "description": "Resource ID of the central Log Analytics workspace for diagnostic logs.",
      "strongType": "omsWorkspace"
    },
    "defaultValue": ""
  },
  "allowedLocations": {
    "type": "Array",
    "metadata": {
      "displayName": "Allowed Locations",
      "description": "Azure regions where resources are permitted.",
      "strongType": "location"
    },
    "defaultValue": ["eastus2", "westus2", "northeurope"]
  },
  "auditEffect": {
    "type": "String",
    "metadata": { "displayName": "Audit Effect" },
    "defaultValue": "AuditIfNotExists",
    "allowedValues": ["AuditIfNotExists", "Disabled"]
  },
  "retentionDays": {
    "type": "Integer",
    "metadata": { "displayName": "Log Retention Days" },
    "defaultValue": 90
  }
}

// policyDefinitions[] entry — three parameter wiring forms
[
  {
    "policyDefinitionId": "/providers/Microsoft.Management/managementGroups/mg-corp/providers/Microsoft.Authorization/policyDefinitions/audit-vm-law-agent",
    "policyDefinitionReferenceId": "auditVmLawAgent",
    "parameters": {
      // Form 1: Thread from initiative parameter
      "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" },

      // Form 2: Effect switch (also threaded, but for the effect field)
      "effect": { "value": "[parameters('auditEffect')]" }
    }
  },
  {
    "policyDefinitionId": "/providers/Microsoft.Authorization/policyDefinitions/e765b5de-1225-4ba3-bd56-1ac6695af988",
    "policyDefinitionReferenceId": "allowedLocations",
    "parameters": {
      // Form 3: Hardcoded — value fixed in the initiative, cannot be overridden at assignment
      "listOfAllowedLocations": { "value": ["eastus2", "westus2"] }
    }
  }
]

// Initiative parameter declaration for the above references
{
  "logAnalyticsWorkspaceId": { "type": "String" },
  "auditEffect": {
    "type": "String",
    "defaultValue": "AuditIfNotExists",
    "allowedValues": ["AuditIfNotExists", "Disabled"]
  }
  // Note: allowedLocations is NOT declared as an initiative parameter
  // because the value is hardcoded — no assignment override needed
}

// Initiative with one logAnalyticsWorkspaceId flowing to five policy references
{
  "parameters": {
    "logAnalyticsWorkspaceId": { "type": "String" }
  },
  "policyDefinitions": [
    {
      "policyDefinitionReferenceId": "auditVmLawAgent",
      "parameters": {
        "workspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
      }
    },
    {
      "policyDefinitionReferenceId": "deployKvDiag",
      "parameters": {
        "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
      }
    },
    {
      "policyDefinitionReferenceId": "deployStorageDiag",
      "parameters": {
        "workspaceResourceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
      }
    },
    {
      "policyDefinitionReferenceId": "auditSqlAuditSettings",
      "parameters": {
        "workspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
      }
    },
    {
      "policyDefinitionReferenceId": "auditKvDiagSettings",
      "parameters": {
        "logAnalyticsWorkspaceId": { "value": "[parameters('logAnalyticsWorkspaceId')]" }
      }
    }
  ]
}
// At assignment time: supply one workspace ID.
// It flows to all five policy references automatically.

# variables.tf — surface initiative-level values as Terraform variables
variable "log_analytics_workspace_id" {
  type        = string
  description = "Resource ID of the central Log Analytics workspace"
}

variable "allowed_locations" {
  type        = list(string)
  description = "Azure regions where resources may be deployed"
  default     = ["eastus2", "westus2"]
}

variable "environment_tier" {
  type        = string
  description = "dev | staging | prod — controls effect strictness"
  validation {
    condition     = contains(["dev", "staging", "prod"], var.environment_tier)
    error_message = "environment_tier must be dev, staging, or prod"
  }
}

# locals.tf — derive effect values from environment_tier
locals {
  deny_effect  = var.environment_tier == "prod" ? "Deny" : (var.environment_tier == "staging" ? "Audit" : "Disabled")
  audit_effect = var.environment_tier == "dev" ? "Disabled" : "AuditIfNotExists"
}

# initiative.tf
resource "azurerm_policy_set_definition" "corp_baseline" {
  name         = "corp-security-baseline"
  policy_type  = "Custom"
  display_name = "Corporate Security Baseline"

  parameters = jsonencode({
    logAnalyticsWorkspaceId = {
      type = "String"
      metadata = {
        displayName = "Log Analytics Workspace ID"
        strongType  = "omsWorkspace"
      }
    }
    allowedLocations = {
      type = "Array"
      metadata = {
        displayName = "Allowed Locations"
        strongType  = "location"
      }
      defaultValue = ["eastus2", "westus2"]
    }
    auditVmAgentEffect = {
      type         = "String"
      defaultValue = "AuditIfNotExists"
      allowedValues = ["AuditIfNotExists", "Disabled"]
    }
    denyPublicStorageEffect = {
      type         = "String"
      defaultValue = "Deny"
      allowedValues = ["Audit", "Deny", "Disabled"]
    }
  })

  policy_definition_reference {
    policy_definition_id = azurerm_policy_definition.audit_vm_law_agent.id
    reference_id         = "auditVmLawAgent"
    parameter_values = jsonencode({
      logAnalyticsWorkspaceId = { value = "[parameters('logAnalyticsWorkspaceId')]" }
      effect                  = { value = "[parameters('auditVmAgentEffect')]" }
    })
  }

  policy_definition_reference {
    policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/34c877ad-507e-4c82-993e-3452a6e0ad3c"
    reference_id         = "denyPublicStorage"
    parameter_values = jsonencode({
      effect = { value = "[parameters('denyPublicStorageEffect')]" }
    })
  }

  policy_definition_reference {
    policy_definition_id = "/providers/Microsoft.Authorization/policyDefinitions/e765b5de-1225-4ba3-bd56-1ac6695af988"
    reference_id         = "allowedLocations"
    parameter_values = jsonencode({
      listOfAllowedLocations = { value = "[parameters('allowedLocations')]" }
    })
  }
}

resource "azurerm_management_group_policy_assignment" "corp_baseline" {
  name                 = "corp-baseline-${var.environment_tier}"
  management_group_id  = var.corp_mg_id
  policy_definition_id = azurerm_policy_set_definition.corp_baseline.id

  parameters = jsonencode({
    logAnalyticsWorkspaceId = { value = var.log_analytics_workspace_id }
    allowedLocations        = { value = var.allowed_locations }
    auditVmAgentEffect      = { value = local.audit_effect }
    denyPublicStorageEffect = { value = local.deny_effect }
  })
}
